pub fn from_db(db: std::sync::Arc<Database>) -> Result<Self> {
        let write_txn = db.begin_write()
            .map_err(|e| CorviaError::Agent(format!("Failed to begin write txn: {e}")))?;
        { let _ = write_txn.open_table(AGENTS); }
        write_txn.commit()
